const clima = $input.first().json;

// 1. Extraemos el clima actual (es un solo bloque, así que lo dejamos casi igual)
const actual = clima.current || {};

// 2. Procesamos el pronóstico DIARIO (Convertimos listas a objetos)
const d = clima.daily || {};
let dailyOrdenado = [];
if (d.time) {
    for (let i = 0; i < d.time.length; i++) {
        dailyOrdenado.push({
            fecha: d.time[i],
            clima_codigo: d.weather_code[i],
            temp_max: d.temperature_2m_max[i],
            temp_min: d.temperature_2m_min[i],
            precipitacion_mm: d.precipitation_sum[i],
            evapotranspiracion: d.et0_fao_evapotranspiration[i],
            prob_precipitacion_pct: d.precipitation_probability_max[i]
        });
    }
}

// 3. Procesamos el pronóstico POR HORA (Convertimos listas a objetos)
const h = clima.hourly || {};
let hourlyOrdenado = [];
if (h.time) {
    for (let i = 0; i < h.time.length; i++) {
        hourlyOrdenado.push({
            hora: h.time[i],
            temp: h.temperature_2m[i],
            punto_rocio: h.dew_point_2m[i],
            nubosidad_total: h.cloud_cover[i],
            nubosidad_baja: h.cloud_cover_low[i],
            nubosidad_media: h.cloud_cover_mid[i],
            nubosidad_alta: h.cloud_cover_high[i],
            viento_950hPa: h.wind_speed_950hPa[i],
            viento_850hPa: h.wind_speed_850hPa[i],
            viento_700hPa: h.wind_speed_700hPa[i],
            viento_300hPa: h.wind_speed_300hPa[i],
            cape: h.cape[i],
            lifted_index: h.lifted_index[i]
        });
    }
}

// 4. Empaquetamos todo en una estructura hermosa y profesional
const reporteEstructurado = {
    ubicacion: { latitud: clima.latitude, longitud: clima.longitude },
    clima_actual: actual,
    pronostico_diario: dailyOrdenado,
    pronostico_por_hora: hourlyOrdenado
};

// 5. ¡LA MAGIA ANTI-ERRORES! 
// Convertimos el JSON final en una cadena de texto (Stringify). 
// Así Gemini recibe texto plano estructurado y jamás vuelve a tirar el error de 'parts'.
return [{ json: { response: JSON.stringify(reporteEstructurado) } }];
